////  DashboardView.swift//  FinanceApp////  Created by user271129 on 5/28/26.//import SwiftUIstruct DashboardView: View {    @StateObject private var vm = DashboardViewModel()    @State private var showAdd = false    var body: some View {        ZStack(alignment: .bottomTrailing) {            ScrollView {                VStack(alignment: .leading, spacing: 16) {                    // Баланс счёта или общий баланс                    TotalBalanceView(                        total: vm.selectedAccount?.amount ?? vm.totalBalance                    )                    // Выбор счёта                    AccountPicker(                        selected: $vm.selectedAccount,                        accounts: vm.accounts,                        totalBalance: vm.totalBalance                    )                    // Период                    PeriodPicker(period: $vm.period)                    // Переключатель доход/расход                    IncomeExpenseToggle(isExpense: $vm.isExpense)                    // Диаграмма                    CategoryPieChart(categories: vm.categories)                    // Список категорий                    CategoryBreakdownList(                        categories: vm.categories,                        total: vm.periodTotal                    )                }                .padding()            }            Button {                showAdd = true            } label: {                Image(systemName: "plus")                    .font(.system(size: 28, weight: .bold))                    .foregroundColor(.white)                    .padding(20)                    .background(Color.blue)                    .clipShape(Circle())                    .shadow(radius: 6)            }            .padding(.trailing, 20)            .padding(.bottom, 20)        }        // Открытие экрана добавления транзакции        .sheet(isPresented: $showAdd) {            EditTransactionView(                isExpense: vm.isExpense,                onSaved: {                    Task { await vm.reloadData() }                }            )        }        // Загрузка данных        .task { await vm.load() }        // Обновление при изменениях        .onChange(of: vm.selectedAccount) { _ in Task { await vm.reloadData() } }        .onChange(of: vm.period) { _ in Task { await vm.reloadData() } }        .onChange(of: vm.isExpense) { _ in Task { await vm.reloadData() } }            }}